export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export type CSVRow = Record<string, unknown>;

export interface CSVResult {
  rows: CSVRow[];
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: CSVRow) => boolean): CSVRow[];
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<unknown, CSVRow[]>;
}

class CSVResultImpl implements CSVResult {
  public rows: CSVRow[];
  public headers: string[];
  public errors: CSVError[];

  constructor(rows: CSVRow[], headers: string[], errors: CSVError[]) {
    this.rows = rows;
    this.headers = headers;
    this.errors = errors;
  }

  filter(predicate: (row: CSVRow) => boolean): CSVRow[] {
    return this.rows.filter(predicate);
  }

  sum(column: string): number {
    let total = 0;
    for (const row of this.rows) {
      const value = row[column];
      if (typeof value === "number" && Number.isFinite(value)) {
        total += value;
      }
    }
    return total;
  }

  average(column: string): number {
    let total = 0;
    let count = 0;
    for (const row of this.rows) {
      const value = row[column];
      if (typeof value === "number" && Number.isFinite(value)) {
        total += value;
        count += 1;
      }
    }
    return count === 0 ? 0 : total / count;
  }

  count(): number {
    return this.rows.length;
  }

  groupBy(column: string): Map<unknown, CSVRow[]> {
    const groups = new Map<unknown, CSVRow[]>();
    for (const row of this.rows) {
      const key = row[column];
      const group = groups.get(key);
      if (group) {
        group.push(row);
      } else {
        groups.set(key, [row]);
      }
    }
    return groups;
  }
}

interface ParsedRow {
  rowNumber: number;
  fields: string[];
}

function coerceValue(raw: string): unknown {
  const trimmed = raw.trim();
  if (trimmed === "" || /^null$/i.test(trimmed)) {
    return null;
  }
  if (/^true$/i.test(trimmed)) {
    return true;
  }
  if (/^false$/i.test(trimmed)) {
    return false;
  }
  if (/^-?\d+(\.\d+)?$/.test(trimmed)) {
    return Number(trimmed);
  }
  return raw;
}

function parseRows(
  input: string,
  delimiter: string,
  quote: string,
  lineSeparator?: string
): { rows: ParsedRow[]; errors: CSVError[] } {
  const rows: ParsedRow[] = [];
  const errors: CSVError[] = [];
  let currentField = "";
  let currentRow: string[] = [];
  let inQuotes = false;
  let rowNumber = 1;
  let lastTokenWasDelimiter = false;

  const matchDelimiter = (index: number): number => {
    if (input.startsWith(delimiter, index)) {
      return delimiter.length;
    }
    return 0;
  };

  const matchLineSeparator = (index: number): number => {
    if (lineSeparator !== undefined) {
      return input.startsWith(lineSeparator, index) ? lineSeparator.length : 0;
    }
    if (input[index] === "\r" && input[index + 1] === "\n") {
      return 2;
    }
    if (input[index] === "\n" || input[index] === "\r") {
      return 1;
    }
    return 0;
  };

  for (let i = 0; i < input.length; ) {
    const char = input[i];
    if (inQuotes) {
      if (char === quote) {
        if (input[i + 1] === quote) {
          currentField += quote;
          i += 2;
        } else {
          inQuotes = false;
          i += 1;
        }
      } else {
        currentField += char;
        i += 1;
      }
      lastTokenWasDelimiter = false;
      continue;
    }

    const delimiterLength = matchDelimiter(i);
    if (delimiterLength > 0) {
      currentRow.push(currentField);
      currentField = "";
      i += delimiterLength;
      lastTokenWasDelimiter = true;
      continue;
    }

    const lineLength = matchLineSeparator(i);
    if (lineLength > 0) {
      currentRow.push(currentField);
      currentField = "";
      rows.push({ rowNumber, fields: currentRow });
      currentRow = [];
      rowNumber += 1;
      i += lineLength;
      lastTokenWasDelimiter = false;
      continue;
    }

    if (char === quote) {
      inQuotes = true;
      i += 1;
      lastTokenWasDelimiter = false;
      continue;
    }

    currentField += char;
    lastTokenWasDelimiter = false;
    i += 1;
  }

  if (inQuotes) {
    errors.push({ row: rowNumber, message: "Unclosed quoted field" });
    return { rows, errors };
  }

  if (currentRow.length > 0 || currentField.length > 0 || lastTokenWasDelimiter) {
    currentRow.push(currentField);
    rows.push({ rowNumber, fields: currentRow });
  }

  return { rows, errors };
}

export function parseCSV(input: string, options: CSVOptions = {}): CSVResult {
  const delimiter = options.delimiter ?? ",";
  const quote = options.quote ?? '"';
  const lineSeparator = options.lineSeparator;

  if (input.length === 0) {
    return new CSVResultImpl([], [], []);
  }

  const { rows: parsedRows, errors } = parseRows(input, delimiter, quote, lineSeparator);

  if (parsedRows.length === 0) {
    return new CSVResultImpl([], [], errors);
  }

  const headerRow = parsedRows[0].fields;
  const headers = headerRow.map((header) => String(header));
  const dataRows: CSVRow[] = [];
  const allErrors = [...errors];

  for (let i = 1; i < parsedRows.length; i += 1) {
    const { rowNumber, fields } = parsedRows[i];
    if (fields.length !== headers.length) {
      allErrors.push({
        row: rowNumber,
        message: `Malformed row: expected ${headers.length} fields but got ${fields.length}`,
      });
      continue;
    }

    const row: CSVRow = {};
    for (let j = 0; j < headers.length; j += 1) {
      row[headers[j]] = coerceValue(fields[j]);
    }
    dataRows.push(row);
  }

  return new CSVResultImpl(dataRows, headers, allErrors);
}

import { parseCSV } from "./csv-parser";

function assert(condition: boolean, message: string): void {
  if (!condition) {
    throw new Error(`Assertion failed: ${message}`);
  }
}

function assertDeepEqual(actual: unknown, expected: unknown, message: string): void {
  const actualJson = JSON.stringify(actual);
  const expectedJson = JSON.stringify(expected);
  if (actualJson !== expectedJson) {
    throw new Error(`Assertion failed: ${message}\nExpected: ${expectedJson}\nActual:   ${actualJson}`);
  }
}

// Basic parsing
{
  const input = "name,age\nAlice,30\nBob,25";
  const result = parseCSV(input);
  assertDeepEqual(result.headers, ["name", "age"], "headers should parse");
  assert(result.rows.length === 2, "should have two rows");
  assertDeepEqual(result.rows[0], { name: "Alice", age: 30 }, "first row parsed");
  assertDeepEqual(result.rows[1], { name: "Bob", age: 25 }, "second row parsed");
}

// Quoted fields with commas
{
  const input = "name,comment\nAlice,\"hello, world\"";
  const result = parseCSV(input);
  assert(result.rows.length === 1, "quoted field rows count");
  assertDeepEqual(result.rows[0], { name: "Alice", comment: "hello, world" }, "quoted comma field");
}

// Escaped quotes
{
  const input = "name,quote\nAlice,\"She said \"\"hi\"\"\"";
  const result = parseCSV(input);
  assertDeepEqual(result.rows[0], { name: "Alice", quote: "She said \"hi\"" }, "escaped quotes parsed");
}

// Custom delimiters and line separator
{
  const input = "id;value|1;first|2;second";
  const result = parseCSV(input, { delimiter: ";", lineSeparator: "|" });
  assertDeepEqual(result.headers, ["id", "value"], "custom headers parsed");
  assertDeepEqual(result.rows, [
    { id: 1, value: "first" },
    { id: 2, value: "second" },
  ], "custom delimiter rows parsed");
}

// Type coercion
{
  const input = "a,b,c,d,e,f,g\n1,2.5,true,FALSE,NULL,hello,";
  const result = parseCSV(input);
  const row = result.rows[0];
  assert(row.a === 1, "integer coercion");
  assert(row.b === 2.5, "float coercion");
  assert(row.c === true, "boolean true coercion");
  assert(row.d === false, "boolean false coercion");
  assert(row.e === null, "null coercion");
  assert(row.f === "hello", "string stays");
  assert(row.g === null, "empty string coerces to null");
}

// Malformed row error collection
{
  const input = "a,b\n1\n2,3,4\n5,6";
  const result = parseCSV(input);
  assert(result.errors.length === 2, "errors collected for malformed rows");
  assertDeepEqual(result.errors.map((error) => error.row), [2, 3], "error row numbers");
  assert(result.rows.length === 1, "only well-formed row included");
  assertDeepEqual(result.rows[0], { a: 5, b: 6 }, "well-formed row parsed");
}

// Filter functionality
{
  const input = "name,age\nAlice,30\nBob,25\nCara,40";
  const result = parseCSV(input);
  const filtered = result.filter((row) => (row.age as number) > 29);
  assert(filtered.length === 2, "filter should return matching rows");
  assertDeepEqual(filtered.map((row) => row.name), ["Alice", "Cara"], "filter results");
}

// Aggregation methods
{
  const input = "name,age,active\nAlice,30,true\nBob,25,false\nCara,45,true";
  const result = parseCSV(input);
  assert(result.count() === 3, "count aggregation");
  assert(result.sum("age") === 100, "sum aggregation");
  assert(result.average("age") === 100 / 3, "average aggregation");
  const groups = result.groupBy("active");
  assert(groups.get(true)?.length === 2, "groupBy true count");
  assert(groups.get(false)?.length === 1, "groupBy false count");
}

// Edge cases: empty input
{
  const result = parseCSV("");
  assertDeepEqual(result.headers, [], "empty headers");
  assert(result.rows.length === 0, "empty rows");
  assert(result.errors.length === 0, "empty errors");
}

// Edge cases: single column
{
  const input = "name\nAlice\nBob";
  const result = parseCSV(input);
  assertDeepEqual(result.headers, ["name"], "single column header");
  assertDeepEqual(result.rows, [{ name: "Alice" }, { name: "Bob" }], "single column rows");
}

// Edge cases: single row
{
  const input = "name,age\nAlice,30";
  const result = parseCSV(input);
  assert(result.rows.length === 1, "single row count");
  assertDeepEqual(result.rows[0], { name: "Alice", age: 30 }, "single row content");
}

// Edge cases: very large fields
{
  const largeField = "a".repeat(10000);
  const input = `data\n${largeField}`;
  const result = parseCSV(input);
  assert(result.rows.length === 1, "large field row count");
  assert(result.rows[0].data === largeField, "large field content");
}

console.log("All tests passed.");

